-- DE — planet_sign (Sonne im jeweiligen Zeichen)
-- ═══════════════════════════════════════════════════════════
('82000000-0000-4000-8000-000000000001','planet_sign','sun','aries',NULL,'de','Sonne im Widder','Mut, die Energie des Neuanfangs und der Drang, deinen eigenen Weg zu gehen, sind dir angeboren. Lange nachzudenken, bevor du losläufst, langweilt dich; Handeln ist dein größter Lehrer. Deine Führungsader ist klar sichtbar — auch wenn niemand es sagt, gehst du intuitiv voran und übernimmst die Führung.','Mutig, voller Aufbruchsenergie, ein geborener Anführer.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000002','planet_sign','sun','taurus',NULL,'de','Sonne im Stier','Beständigkeit, greifbare Schönheit und dein eigenes Tempo sind dir heilig. Wer hetzt, dem begegnest du mit Misstrauen, und du gibst deinen eigenen Rhythmus nicht auf. Liebe, Geld, Natur — was auch immer durch deine fünf Sinne wirklich für dich ist, bildet das Fundament deines Lebens.','Beständig, sinnlich, im eigenen Rhythmus voranschreitend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000003','planet_sign','sun','gemini',NULL,'de','Sonne in den Zwillingen','Neugier, Worte und Verbindung — deine drei Säulen. Du kannst jedes Thema lernen, aber dich auf ein einziges festzulegen, erdrückt dich. Dein Leben braucht Vielfalt, Flexibilität und ständig neue Fragen; Eintönigkeit erstickt deinen Geist.','Neugierig, vielseitig, kommunikationsfreudig.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000004','planet_sign','sun','cancer',NULL,'de','Sonne im Krebs','Emotionales Gedächtnis, Familie und Zugehörigkeit geben dir Halt. Du kannst verbergen, was du fühlst, aber du vergisst es nie. Am stärksten bist du, wenn du mit deinen Liebsten ein Zuhause — ob physisch oder emotional — aufbaust.','Starkes emotionales Gedächtnis, beschützend, auf Zugehörigkeit ausgerichtet.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000005','planet_sign','sun','leo',NULL,'de','Sonne im Löwen','In dir gibt es einen Teil, der leuchten muss — das Gefühl, dass die Bühne dir gehört, kommt nicht von ungefähr. Du willst nicht aus Eitelkeit wahrgenommen werden, sondern weil du es verdient hast. Dein großzügiges Herz ist, sobald du ihm vertrauen lernst, deine größte Stärke.','Großzügig, gesehen werden wollend, mit warmem Leuchten.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000006','planet_sign','sun','virgo',NULL,'de','Sonne in der Jungfrau','Liebe zum Detail, Dienst und das Streben nach Vervollkommnung. Du kommst nicht zur Ruhe, bevor eine Aufgabe ordentlich erledigt ist; das ist keine Pedanterie, sondern eine innere Berufung. Deine Kritik richtet sich zuerst gegen dich selbst — deshalb kannst du auf andere hart wirken.','Liebe zum Detail, Arbeitsethik, stetige Verbesserung.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000007','planet_sign','sun','libra',NULL,'de','Sonne in der Waage','Gleichgewicht, Ästhetik und Beziehung — die drei Schläge deines Herzens. Selbst wenn du allein bist, blickst du durch die Augen eines anderen. Bei Entscheidungen beide Seiten zu sehen, macht dich gerecht; doch lässt es dich manchmal auch unentschlossen erscheinen.','Beziehungsorientiert, ästhetisch empfindsam, nach Ausgleich strebend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000008','planet_sign','sun','scorpio',NULL,'de','Sonne im Skorpion','Mit der Oberfläche gibst du dich nicht zufrieden — die Wahrheit liegt unter allem, und dorthin gehst du. Du bindest dich intensiv und lebst intensiv. Zerstörung und Wiedergeburt sind der Rhythmus deines Lebens; wenn du ihn annimmst statt ihn abzulehnen, verwandelst du dich.','Tiefgründig, verwandelnd, intensiv bindend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000009','planet_sign','sun','sagittarius',NULL,'de','Sonne im Schützen','Horizonte, Sinn und Freiheit rufen dich. Bei niemandem, der dich einengt, bleibst du lange; ob mit dem Körper oder dem Geist, du reist stets in die Ferne und lotest Grenzen aus. Philosophie, Reisen, Bildung — dort wächst du.','Weitblickend, freiheitsliebend, nach Sinn suchend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000010','planet_sign','sun','capricorn',NULL,'de','Sonne im Steinbock','Disziplin, Verantwortung und der lange Atem — deine Ernsthaftigkeit ist kein Luxus, sondern Teil deiner Persönlichkeit. Schon in jungen Jahren wirkst du reif; mit dem Alter wirst du leichter und entdeckst das Vergnügen. Du gehst hartnäckig auf dein Ziel zu und fürchtest dich nicht davor, spät zu kommen.','Diszipliniert, zielorientiert, langfristig denkend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000011','planet_sign','sun','aquarius',NULL,'de','Sonne im Wassermann','Das Selbstverständliche zu hinterfragen, ist dir überall dort angeboren, wo du dich als anders abhebst. Die Gemeinschaft liegt dir am Herzen, doch du sprichst nicht die Sprache der Masse. Du liest die Zukunft aus der Gegenwart — deshalb wirst du manchmal missverstanden.','Originell, hinterfragend, in die Zukunft blickend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000012','planet_sign','sun','pisces',NULL,'de','Sonne in den Fischen','Deine Grenzen sind durchlässig — du nimmst sowohl die Schönheit als auch die Schwere in dich auf. Du bist kreativ, intuitiv und mitfühlend. Um dich nicht selbst zu verlieren, musst du lernen, hin und wieder physische Grenzen zu setzen.','Intuitiv, mitfühlend, kreativ, durchlässig.','warm',NULL,NULL,1,NULL,NULL),

-- ═══════════════════════════════════════════════════════════
-- DE — aspect
-- ═══════════════════════════════════════════════════════════
('82000000-0000-4000-8000-000000000020','aspect','sun','moon','trine','de','Sonne ↔ Mond (harmonischer Aspekt / Trigon)','Dein inneres „das sollte ich tun" und „das möchte ich fühlen" blicken meist in dieselbe Richtung. Du selbst zu sein, fällt dir nicht schwer; deine rationalen Entscheidungen decken sich in der Regel mit deinen emotionalen Bedürfnissen.','Dein Denken und dein Fühlen sind im Einklang.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000021','aspect','sun','moon','square','de','Sonne ↔ Mond (Spannungsaspekt / Quadrat)','In dir verhandeln ständig zwei Stimmen: „ich müsste dies tun" gegen „aber ich fühle das nicht". Diese Spannung mag ermüdend wirken, doch sie ist der Motor eines tiefen Selbstbewusstseins — du lernst, sowohl deinen Verstand als auch dein Herz einzubeziehen.','Fähig, die Spannung zwischen Verstand und Herz zu verwandeln.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000022','aspect','mars','saturn','square','de','Mars ↔ Saturn (Spannungsaspekt / Quadrat)','Dein Impuls „sofort handeln" und deine Stimme „denk nach, mach einen Plan" liegen in ständigem Widerstreit. Dieser Konflikt bewahrt dich vor voreiligen Entscheidungen, kann dich aber manchmal lähmen. Mit der Zeit lernst du, dein eigenes Gleichgewicht zwischen Handeln und Geduld zu finden.','Die Spannung zwischen Handeln und Geduld.','professional',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000023','aspect','venus','jupiter','sextile','de','Venus ↔ Jupiter (harmonischer Aspekt / Sextil)','Liebe auszudrücken fällt dir leicht. Du bist großzügig und gibst deinen Liebsten reichlich; geben, ohne eine Gegenleistung zu erwarten, nährt deine Seele. Du neigst dazu, die schönen Momente des Lebens zu bemerken — das ist kein Zufall, sondern eine Gabe.','Großzügig, die Schönheit des Lebens sehend.','warm',NULL,NULL,1,NULL,NULL),
('82000000-0000-4000-8000-000000000024','aspect','sun','pluto','conjunction','de','Sonne ⊕ Pluto (Konjunktion)','Deine Identität ist mit einer intensiven, verwandelnden Kraft verwoben. Zusammenbrüche und Wiedergeburten sind in deinem Leben gewöhnlich; aus jeder Krise gehst du als ein anderes Selbst hervor. Machtdynamiken ziehen dich an und stellen dich, ob du willst oder nicht, auf die Probe.','Eine durch Wandlung definierte Identität.','direct',NULL,NULL,1,NULL,NULL),

-- ═══════════════════════════════════════════════════════════
-- DE — sign_house
-- ═══════════════════════════════════════════════════════════
('82000000-0000-4000-8000-000000000040','sign_house','scorpio','8',NULL,'de','Skorpion im 8. Haus','Das 8. Haus ist das Haus der Verwandlung, der gemeinsamen Ressourcen und des Verborgenen. Mit dem Skorpion hier werden diese Themen noch intensiver: tiefe Beziehungen, Erbe und das Herauskommen aus Krisen sind dein natürlicher Boden. An der Oberfläche zu bleiben, verunsichert dich; du hast einen inneren Drang, das Wirkliche zu sehen.','Ein Feld tiefer Verwandlung.','professional',NULL,NULL,1,NULL,NULL),

-- ═══════════════════════════════════════════════════════════
-- DE — misc (redaktionelle Kontextnotizen aus Wikipedia)
-- ═══════════════════════════════════════════════════════════
('82100000-0000-4000-8000-000000000001','misc','wiki_astrology','overview',NULL,'de','Wikipedia-Import — Überblick über die Astrologie','Astrologie wird als eine historische Deutungstradition behandelt, die Bedeutungsbeziehungen zwischen Himmelskörpern und menschlichem Charakter, Verhaltensmustern und Lebensereignissen herstellt. In der modernen Produktsprache sollte dieses Thema nicht als endgültiges Urteil oder wissenschaftliche Vorhersage dargestellt werden, sondern in einem symbolischen, kulturellen und auf Selbstwahrnehmung ausgerichteten Rahmen verwendet werden.','Eine allgemeine Notiz, die die Astrologie als kulturelle und symbolische Deutungstradition verortet.','neutral','https://de.wikipedia.org/wiki/Astrologie','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000002','misc','wiki_astrology','science_caution',NULL,'de','Wikipedia-Import — Hinweis zur wissenschaftlichen Sprache','Bei der Erstellung von Astrologie-Inhalten sollte der Anspruch wissenschaftlicher Gewissheit vermieden werden. Die dem Nutzer angebotenen Deutungen sollten nicht wie wiederholbare experimentelle Ergebnisse geschrieben werden, sondern als Leittexte, die in der Sprache von Symbolen, Archetypen und Selbstwahrnehmung erklärt werden.','Ein Hinweis, in Astrologie-Deutungen auf den Anspruch wissenschaftlicher Gewissheit zu verzichten.','professional','https://de.wikipedia.org/wiki/Astrologie','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000003','misc','wiki_astrology','barnum_effect',NULL,'de','Wikipedia-Import — Notiz zum Barnum-Effekt','Dass allgemeine und schmeichelhafte Aussagen als persönlich zutreffend wahrgenommen werden, ist ein bedeutendes psychologisches Risiko in der Astrologie-Erfahrung. LLM-Ausgaben sollten daher übermäßig vage, für jeden gültige Sätze reduzieren und mit spezifischen Details aus den Geburtsdaten des Nutzers, dem Fragenkontext und vergangenen Interaktionen eine verantwortungsvollere Sprache aufbauen.','Ein Barnum-Effekt-Hinweis zur Reduzierung allgemeingültiger Deutungen.','professional','https://de.wikipedia.org/wiki/Astrologie','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000004','misc','wiki_zodiac','geometry',NULL,'de','Wikipedia-Import — Geometrie des Tierkreises','Bei der Beschreibung des Tierkreises kann daran erinnert werden, dass der 360-Grad-Himmelskreis symbolisch in zwölf gleiche Teile geteilt wird. Jeder Abschnitt wird als ein Bereich von 30 Grad behandelt; dieser Ansatz beschreibt die astrologische Symbolordnung eher als die Grenzen der Sternbilder.','Die Teilung des Tierkreises in zwölf gleiche symbolische Abschnitte.','neutral','https://de.wikipedia.org/wiki/Tierkreiszeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000005','misc','wiki_zodiac','constellations',NULL,'de','Wikipedia-Import — Tierkreis und Sternbilder','Der Tierkreisgürtel steht in Beziehung zu den astronomischen Sternbildern; die in der Astrologie verwendeten Tierkreiszeichen sind jedoch nicht direkt dasselbe wie die modernen Sternbildgrenzen. Wenn diese Unterscheidung in den Inhalten schlicht getroffen wird, werden sowohl der SEO-Text als auch das Vertrauen der Nutzer gestärkt.','Die Unterscheidung zwischen Tierkreiszeichen und astronomischen Sternbildgrenzen.','neutral','https://de.wikipedia.org/wiki/Tierkreiszeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000006','misc','wiki_zodiac','ecliptic',NULL,'de','Wikipedia-Import — Kontext der Ekliptik','In Zeichen- und Tierkreistexten kann der Kontext der Ekliptik, der mit der scheinbaren jährlichen Bahn der Sonne am Himmel verbunden ist, als kurzer Hintergrund verwendet werden. Diese Information hilft den Zeichenseiten, statt eines bloßen „Persönlichkeitsetiketts" die Idee von Himmelskoordinaten und Zyklen zu vermitteln.','Ein kurzer Hintergrund, der das Konzept der Ekliptik mit den Zeichenbeschreibungen verknüpft.','neutral','https://de.wikipedia.org/wiki/Sternzeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000007','misc','wiki_signs','elements',NULL,'de','Wikipedia-Import — Beschreibung der Elemente','Die Elemente Feuer, Erde, Luft und Wasser können in Zeicheninhalten verwendet werden, um das grundlegende Temperament zu erklären. Die Texte sollten Stereotypisierung vermeiden; das Element sollte nicht für sich allein wie ein Schicksal dargestellt werden, sondern als eine Sprache der Tendenz, die zusammen mit den anderen Stellungen im Geburtshoroskop gelesen wird.','Eine Notiz, die die Elemente ohne Stereotype mit dem gesamten Horoskop verknüpft.','warm','https://de.wikipedia.org/wiki/Sternzeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000008','misc','wiki_signs','modalities',NULL,'de','Wikipedia-Import — Beschreibung der Modalitäten','Die kardinalen, fixen und veränderlichen Modalitäten sind eine gute redaktionelle Ebene, um die Handlungsweise eines Zeichens zu erklären. In Profiltexten sollte die Modalität mit schlichten Beispielen anhand der Rhythmen des Beginnens, des Aufrechterhaltens und des Anpassens erklärt werden.','Eine Notiz, die die Modalitäten in der Sprache von Handlungsweise und Rhythmus erklärt.','warm','https://de.wikipedia.org/wiki/Sternzeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000009','misc','wiki_birth_chart','chart_context',NULL,'de','Wikipedia-Import — Kontext des Geburtshoroskops','Beim Übergang von den Zeichenseiten zum Geburtshoroskop sollte dem Nutzer klar gesagt werden, dass das Sonnenzeichen allein nicht die ganze Persönlichkeit erklärt. Zusammen mit dem Mond, dem Aszendenten, den Planeten, den Häusern und den Aspekten entsteht ein vielschichtigeres Bild.','Eine CTA-Notiz für den Übergang vom Sonnenzeichen zum gesamten Geburtshoroskop.','professional','https://de.wikipedia.org/wiki/Sternzeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000010','misc','wiki_astrology','traditions',NULL,'de','Wikipedia-Import — Astrologische Traditionen','Die Astrologie hat in verschiedenen Kulturen unterschiedliche Traditionen, Gattungen und Anwendungsbereiche. In den Inhalten von GoldMoodAstro sollte diese Vielfalt in der Sprache von „Deutungsschulen" und „symbolischen Ansätzen" vermittelt werden statt in der Erzählung eines einzigen absoluten Systems.','Eine Notiz, die verschiedene astrologische Traditionen pluralistisch vermittelt.','neutral','https://de.wikipedia.org/wiki/Astrologie','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000011','misc','wiki_astrology','responsible_copy',NULL,'de','Wikipedia-Import — Standard für verantwortungsvolle Texte','Astrologie-Texte sollten sich von beängstigenden, fatalistischen oder ein sicheres Ergebnis versprechenden Aussagen fernhalten. Der sicherste Rahmen im Nutzererlebnis ist ein beratender Ton, der Wahrscheinlichkeit, Bewusstsein, die Sprache der Gefühle und den Raum für Entscheidungen betont.','Ein Produktsprach-Standard, der fatalistische und beängstigende Aussagen vermeidet.','professional','https://de.wikipedia.org/wiki/Astrologie','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL),
('82100000-0000-4000-8000-000000000012','misc','wiki_zodiac','editorial_seo',NULL,'de','Wikipedia-Import — Redaktionelle SEO-Brücke','Beim Verknüpfen der Zeichen-, Tierkreis- und Geburtshoroskop-Seiten sollte zuerst das Grundkonzept erklärt und dann zu einer persönlicheren und detaillierteren Deutung übergegangen werden. Diese Struktur erfüllt sowohl die Suchabsicht als auch führt sie den Nutzer auf natürliche Weise zum Geburtshoroskop-Produkt.','Ein SEO-Inhaltsfluss, der vom Grundkonzept zum persönlichen Horoskop führt.','professional','https://de.wikipedia.org/wiki/Tierkreiszeichen','Wikipedia contributors, CC BY-SA 4.0',0,NULL,NULL)

ON DUPLICATE KEY UPDATE
  title = VALUES(title),
  content = VALUES(content),
  short_summary = VALUES(short_summary);
